primary_snippet.content:
    // For ranges < 2min, use 15sec range
    rangeOffset = 7.5
    rangeUnit = 'second'
  }

  return {
    start: dayjs(datumTimestamp).subtract(rangeOffset, rangeUnit).toISOString(),
    end: dayjs(datumTimestamp).add(rangeOffset, rangeUnit).toISOString(),
  }
}

